it('should not produce duplicate items across consecutive pages', () => {
  const allItems = Array.from({ length: 20 }, (_, i) => i + 1);
  const page1 = paginate(allItems, 1, 5);
  const page2 = paginate(allItems, 2, 5);
  const page3 = paginate(allItems, 3, 5);

  expect(page1.items).toEqual([1, 2, 3, 4, 5]);
  expect(page2.items).toEqual([6, 7, 8, 9, 10]);
  expect(page3.items).toEqual([11, 12, 13, 14, 15]);

  // Ensure no overlap between pages
  const combined = [...page1.items, ...page2.items, ...page3.items];
  const unique = new Set(combined);
  expect(unique.size).toBe(combined.length);
});

